    // --- XML Parser Factory ---

    private DocumentBuilder createSecureDocumentBuilder() throws ParserConfigurationException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setValidating(false);

        // Security: Disable external entities to prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        return factory.newDocumentBuilder();
    }

    // --- SOAP Message Provider Implementation ---

    @Override
    public SOAPMessage invoke(SOAPMessage request) {
        long requestId = REQUEST_COUNTER.incrementAndGet();
        LOGGER.info("Processing request #" + requestId);

        try {
            SOAPBody requestBody = request.getSOAPBody();
            Node operationNode = getFirstChildElement(requestBody);

            if (operationNode == null) {
                return createFaultResponse("InvalidRequest", "No operation found in SOAP body");
            }

            String operation = operationNode.getLocalName();
            LOGGER.info("Operation: " + operation);

            switch (operation) {
                case "ImportData":
                    return handleImportData(operationNode);
                case "GetImportStatus":
                    return handleGetImportStatus(operationNode);
                case "ProcessEntities":
                    return handleProcessEntities(operationNode);
                case "TransformData":
                    return handleTransformData(operationNode);
                case "BulkImport":
                    return handleBulkImport(operationNode);
                default:
                    return createFaultResponse("UnsupportedOperation",
                            "Operation '" + operation + "' is not supported");
            }

        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "SOAP processing error", e);
            return createFaultResponse("SOAPError", e.getMessage());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error", e);
            return createFaultResponse("InternalError", "An unexpected error occurred: " + e.getMessage());
        }
    }

    // --- Operation Handlers ---

    private SOAPMessage handleImportData(Node operationNode) throws Exception {
        String jobId = UUID.randomUUID().toString();
        LOGGER.info("Starting import job: " + jobId);

        // Parse the XML payload from the operation node
        Document payloadDoc = extractPayloadDocument(operationNode);
        List<DataEntity> entities = parseEntitiesFromDocument(payloadDoc);
        List<String> errors = validateEntities(entities);

        long totalRecords = countAllEntities(entities);
        String status = errors.isEmpty() ? "COMPLETED" : "COMPLETED_WITH_ERRORS";

        ImportJob job = new ImportJob(jobId, status, totalRecords, totalRecords, entities, errors);
        IMPORT_JOBS.put(jobId, job);

        LOGGER.info("Import job " + jobId + " completed. Processed " + totalRecords + " entities with " + errors.size() + " errors");

        return createImportResponse(job);
    }

    private SOAPMessage handleGetImportStatus(Node operationNode) throws Exception {
        String jobId = getElementText(operationNode, "JobId");
        if (jobId == null || jobId.trim().isEmpty()) {
            return createFaultResponse("InvalidRequest", "JobId is required");
        }

        ImportJob job = IMPORT_JOBS.get(jobId);
        if (job == null) {
            return createFaultResponse("JobNotFound", "Import job '" + jobId + "' not found");
        }

        return createStatusResponse(job);
    }

    private SOAPMessage handleProcessEntities(Node operationNode) throws Exception {
        Document payloadDoc = extractPayloadDocument(operationNode);
        List<DataEntity> entities = parseComplexEntities(payloadDoc.getDocumentElement());

        Map<String, Integer> summary = new LinkedHashMap<>();
        summarizeEntities(entities, summary);

        return createProcessResponse(entities.size(), summary);
    }

    private SOAPMessage handleTransformData(Node operationNode) throws Exception {
        String sourceFormat = getElementText(operationNode, "SourceFormat");
        String targetFormat = getElementText(operationNode, "TargetFormat");

        Document payloadDoc = extractPayloadDocument(operationNode);
        List<DataEntity> entities = parseEntitiesFromDocument(payloadDoc);

        // Simulate transformation
        List<DataEntity> transformedEntities = transformEntities(entities, sourceFormat, targetFormat);

        return createTransformResponse(transformedEntities, sourceFormat, targetFormat);
    }

    private SOAPMessage handleBulkImport(Node operationNode) throws Exception {
        String jobId = UUID.randomUUID().toString();
        int batchSize = 1000;

        String batchSizeStr = getElementText(operationNode, "BatchSize");
        if (batchSizeStr != null && !batchSizeStr.isEmpty()) {
            batchSize = Integer.parseInt(batchSizeStr);
        }

        Document payloadDoc = extractPayloadDocument(operationNode);
        List<DataEntity> allEntities = parseEntitiesFromDocument(payloadDoc);

        // Process in batches
        List<String> errors = new ArrayList<>();
        long processedCount = 0;

        for (int i = 0; i < allEntities.size(); i += batchSize) {
            int end = Math.min(i + batchSize, allEntities.size());
            List<DataEntity> batch = allEntities.subList(i, end);

            List<String> batchErrors = validateEntities(batch);
            errors.addAll(batchErrors);
            processedCount += batch.size();

            LOGGER.info("Bulk import batch processed: " + processedCount + "/" + allEntities.size());
        }

        String status = errors.isEmpty() ? "COMPLETED" : "COMPLETED_WITH_ERRORS";
        ImportJob job = new ImportJob(jobId, status, processedCount, allEntities.size(), allEntities, errors);
        IMPORT_JOBS.put(jobId, job);

        return createBulkImportResponse(job, batchSize);
    }

    // --- XML Parsing Methods ---

    private Document extractPayloadDocument(Node operationNode) throws Exception {
        DocumentBuilder builder = createSecureDocumentBuilder();

        // Look for a Payload or Data child element
        Node payloadNode = findChildElement(operationNode, "Payload");
        if (payloadNode == null) {
            payloadNode = findChildElement(operationNode, "Data");
        }
        if (payloadNode == null) {
            payloadNode = operationNode;
        }

        // Serialize the payload node to string and re-parse
        String xmlContent = nodeToString(payloadNode);
        return builder.parse(new InputSource(new StringReader(xmlContent)));
    }

    private List<DataEntity> parseEntitiesFromDocument(Document doc) {
        List<DataEntity> entities = new ArrayList<>();
        Element root = doc.getDocumentElement();

        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                DataEntity entity = parseEntityNode((Element) child);
                if (entity != null) {
                    entities.add(entity);
                }
            }
        }

        return entities;
    }

    private DataEntity parseEntityNode(Element element) {
        String entityType = element.getLocalName() != null ? element.getLocalName() : element.getTagName();
        String entityId = element.getAttribute("id");
        if (entityId.isEmpty()) {
            entityId = getElementText(element, "Id");
            if (entityId == null) {
                entityId = getElementText(element, "ID");
            }
            if (entityId == null) {
                entityId = "auto-" + UUID.randomUUID().toString().substring(0, 8);
            }
        }

        Map<String, String> attributes = new LinkedHashMap<>();
        List<DataEntity> children = new ArrayList<>();

        // Parse XML attributes
        NamedNodeMap xmlAttrs = element.getAttributes();
        for (int i = 0; i < xmlAttrs.getLength(); i++) {
            Node attr = xmlAttrs.item(i);
            if (!attr.getNodeName().startsWith("xmlns")) {
                attributes.put(attr.getNodeName(), attr.getNodeValue());
            }
        }

        // Parse child elements
        NodeList childNodes = element.getChildNodes();
        for (int i = 0; i < childNodes.getLength(); i++) {
            Node child = childNodes.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                if (hasChildElements(childElement)) {
                    // This is a nested entity
                    DataEntity childEntity = parseEntityNode(childElement);
                    if (childEntity != null) {
                        children.add(childEntity);
                    }
                } else {
                    // This is a simple attribute
                    String key = childElement.getLocalName() != null ? childElement.getLocalName() : childElement.getTagName();
                    String value = childElement.getTextContent();
                    attributes.put(key, value != null ? value.trim() : "");
                }
            }
        }

        return new DataEntity(entityType, entityId, attributes, children);
    }

    private List<DataEntity> parseComplexEntities(Element root) {
        List<DataEntity> entities = new ArrayList<>();
        parseNestedStructure(root, entities, 0, 10); // max depth of 10
        return entities;
    }

    private void parseNestedStructure(Element element, List<DataEntity> entities, int depth, int maxDepth) {
        if (depth > maxDepth) {
            LOGGER.warning("Maximum nesting depth reached at element: " + element.getTagName());
            return;
        }

        DataEntity entity = parseEntityNode(element);
        if (entity != null) {
            entities.add(entity);
        }
    }

    // --- Validation ---

    private List<String> validateEntities(List<DataEntity> entities) {
        List<String> errors = new ArrayList<>();

        for (DataEntity entity : entities) {
            if (entity.getEntityType() == null || entity.getEntityType().trim().isEmpty()) {
                errors.add("Entity with id '" + entity.getEntityId() + "' has no type");
            }
            if (entity.getEntityId() == null || entity.getEntityId().trim().isEmpty()) {
                errors.add("Entity of type '" + entity.getEntityType() + "' has no id");
            }

            // Validate required attributes based on entity type
            validateEntityAttributes(entity, errors);

            // Recursively validate children
            if (entity.getChildren() != null && !entity.getChildren().isEmpty()) {
                errors.addAll(validateEntities(entity.getChildren()));
            }
        }

        return errors;
    }

    private void validateEntityAttributes(DataEntity entity, List<String> errors) {
        switch (entity.getEntityType().toLowerCase()) {
            case "customer":
                if (!entity.getAttributes().containsKey("Name") && !entity.getAttributes().containsKey("name")) {
                    errors.add("Customer entity '" + entity.getEntityId() + "' missing 'Name' attribute");
                }
                break;
            case "order":
                if (!entity.getAttributes().containsKey("OrderDate") && !entity.getAttributes().containsKey("orderDate")) {
                    errors.add("Order entity '" + entity.getEntityId() + "' missing 'OrderDate' attribute");
                }
                break;
            case "product":
                if (!entity.getAttributes().containsKey("SKU") && !entity.getAttributes().containsKey("sku")) {
                    errors.add("Product entity '" + entity.getEntityId() + "' missing 'SKU' attribute");
                }
                break;
            default:
                break;
        }
    }

    // --- Transformation ---

    private List<DataEntity> transformEntities(List<DataEntity> entities, String sourceFormat, String targetFormat) {
        List<DataEntity> transformed = new ArrayList<>();
        for (DataEntity entity : entities) {
            Map<String, String> newAttributes = new LinkedHashMap<>(entity.getAttributes());
            newAttributes.put("_sourceFormat", sourceFormat != null ? sourceFormat : "XML");
            newAttributes.put("_targetFormat", targetFormat != null ? targetFormat : "XML");
            newAttributes.put("_transformedAt", new Date().toString());

            List<DataEntity> transformedChildren = transformEntities(entity.getChildren(), sourceFormat, targetFormat);

            transformed.add(new DataEntity(
                    entity.getEntityType(),
                    entity.getEntityId(),
                    newAttributes,
                    transformedChildren
            ));
        }
        return transformed;
    }

    // --- Response Builders ---

    private SOAPMessage createImportResponse(ImportJob job) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement importResponse = body.addChildElement("ImportDataResponse", "edi",
                "http://enterprise.integration/soap");
        importResponse.addChildElement("JobId", "edi").addTextNode(job.getJobId());
        importResponse.addChildElement("Status", "edi").addTextNode(job.getStatus());
        importResponse.addChildElement("RecordsProcessed", "edi").addTextNode(String.valueOf(job.getRecordsProcessed()));
        importResponse.addChildElement("TotalRecords", "edi").addTextNode(String.valueOf(job.getTotalRecords()));

        if (!job.getErrors().isEmpty()) {
            SOAPElement errorsElement = importResponse.addChildElement("Errors", "edi");
            for (String error : job.getErrors()) {
                errorsElement.addChildElement("Error", "edi").addTextNode(error);
            }
        }

        SOAPElement entitiesSummary = importResponse.addChildElement("EntitiesSummary", "edi");
        Map<String, Integer> summary = new LinkedHashMap<>();
        summarizeEntities(job.getEntities(), summary);
        for (Map.Entry<String, Integer> entry : summary.entrySet()) {
            SOAPElement typeCount = entitiesSummary.addChildElement("EntityType", "edi");
            typeCount.setAttribute("name", entry.getKey());
            typeCount.setAttribute("count", String.valueOf(entry.getValue()));
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createStatusResponse(ImportJob job) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement statusResponse = body.addChildElement("GetImportStatusResponse", "edi",
                "http://enterprise.integration/soap");
        statusResponse.addChildElement("JobId", "edi").addTextNode(job.getJobId());
        statusResponse.addChildElement("Status", "edi").addTextNode(job.getStatus());
        statusResponse.addChildElement("RecordsProcessed", "edi").addTextNode(String.valueOf(job.getRecordsProcessed()));
        statusResponse.addChildElement("TotalRecords", "edi").addTextNode(String.valueOf(job.getTotalRecords()));
        statusResponse.addChildElement("ErrorCount", "edi").addTextNode(String.valueOf(job.getErrors().size()));

        response.saveChanges();
        return response;
    }

    private SOAPMessage createProcessResponse(int entityCount, Map<String, Integer> summary) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement processResponse = body.addChildElement("ProcessEntitiesResponse", "edi",
                "http://enterprise.integration/soap");
        processResponse.addChildElement("TotalEntities", "edi").addTextNode(String.valueOf(entityCount));
        processResponse.addChildElement("Status", "edi").addTextNode("PROCESSED");

        SOAPElement summaryElement = processResponse.addChildElement("Summary", "edi");
        for (Map.Entry<String, Integer> entry : summary.entrySet()) {
            SOAPElement typeElement = summaryElement.addChildElement("EntityType", "edi");
            typeElement.setAttribute("name", entry.getKey());
            typeElement.setAttribute("count", String.valueOf(entry.getValue()));
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createTransformResponse(List<DataEntity> entities, String sourceFormat, String targetFormat) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement transformResponse = body.addChildElement("TransformDataResponse", "edi",
                "http://enterprise.integration/soap");
        transformResponse.addChildElement("SourceFormat", "edi").addTextNode(sourceFormat != null ? sourceFormat : "XML");
        transformResponse.addChildElement("TargetFormat", "edi").addTextNode(targetFormat != null ? targetFormat : "XML");
        transformResponse.addChildElement("EntitiesTransformed", "edi").addTextNode(String.valueOf(entities.size()));
        transformResponse.addChildElement("Status", "edi").addTextNode("TRANSFORMED");

        SOAPElement dataElement = transformResponse.addChildElement("TransformedData", "edi");
        for (DataEntity entity : entities) {
            appendEntityToSOAP(dataElement, entity);
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createBulkImportResponse(ImportJob job, int batchSize) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement bulkResponse = body.addChildElement("BulkImportResponse", "edi",
                "http://enterprise.integration/soap");
        bulkResponse.addChildElement("JobId", "edi").addTextNode(job.getJobId());
        bulkResponse.addChildElement("Status", "edi").addTextNode(job.getStatus());
        bulkResponse.addChildElement("BatchSize", "edi").addTextNode(String.valueOf(batchSize));
        bulkResponse.addChildElement("TotalBatches", "edi").addTextNode(
                String.valueOf((int) Math.ceil((double) job.getTotalRecords() / batchSize)));
        bulkResponse.addChildElement("RecordsProcessed", "edi").addTextNode(String.valueOf(job.getRecordsProcessed()));
        bulkResponse.addChildElement("TotalRecords", "edi").addTextNode(String.valueOf(job.getTotalRecords()));
        bulkResponse.addChildElement("ErrorCount", "edi").addTextNode(String.valueOf(job.getErrors().size()));

        response.saveChanges();
        return response;
    }

    private SOAPMessage createFaultResponse(String faultCode, String faultMessage) {
        try {
            MessageFactory factory = MessageFactory.newInstance();
            SOAPMessage response = factory.createMessage();
            SOAPBody body = response.getSOAPBody();

            SOAPFault fault = body.addFault();
            fault.setFaultCode("edi:" + faultCode);
            fault.setFaultString(faultMessage);
            fault.setFaultActor("EnterpriseDataIntegrationService");

            Detail detail = fault.addDetail();
            DetailEntry detailEntry = detail.addDetailEntry(
                    new javax.xml.namespace.QName("http://enterprise.integration/soap", "ErrorDetail", "edi"));
            detailEntry.addChildElement("Timestamp", "edi").addTextNode(new Date().toString());
            detailEntry.addChildElement("RequestId", "edi").addTextNode(
                    String.valueOf(REQUEST_COUNTER.get()));

            response.saveChanges();
            return response;
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Failed to create fault response", e);
            throw new RuntimeException("Failed to create fault response", e);
        }
    }

    // --- Utility Methods ---

    private void appendEntityToSOAP(SOAPElement parent, DataEntity entity) throws SOAPException {
        SOAPElement entityElement = parent.addChildElement("Entity", "edi");
        entityElement.setAttribute("type", entity.getEntityType());
        entityElement.setAttribute("id", entity.getEntityId());

        for (Map.Entry<String, String> attr : entity.getAttributes().entrySet()) {
            entityElement.addChildElement(sanitizeElementName(attr.getKey()), "edi")
                    .addTextNode(attr.getValue());
        }

        if (!entity.getChildren().isEmpty()) {
            SOAPElement childrenElement = entityElement.addChildElement("Children", "edi");
            for (DataEntity child : entity.getChildren()) {
                appendEntityToSOAP(childrenElement, child);
            }
        }
    }

    private String sanitizeElementName(String name) {
        // Remove invalid XML name characters
        String sanitized = name.replaceAll("[^a-zA-Z0-9_.-]", "_");
        if (sanitized.isEmpty() || Character.isDigit(sanitized.charAt(0))) {
            sanitized = "_" + sanitized;
        }
        return sanitized;
    }

    private Node getFirstChildElement(Node parent) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return children.item(i);
            }
        }
        return null;
    }

    private Node findChildElement(Node parent, String localName) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                String name = child.getLocalName() != null ? child.getLocalName() : child.getNodeName();
                if (localName.equals(name)) {
                    return child;
                }
            }
        }
        return null;
    }

    private String getElementText(Node parent, String elementName) {
        Node found = findChildElement(parent, elementName);
        if (found != null) {
            return found.getTextContent();
        }
        return null;
    }

    private boolean hasChildElements(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return true;
            }
        }
        return false;
    }

    private long countAllEntities(List<DataEntity> entities) {
        long count = entities.size();
        for (DataEntity entity : entities) {
            if (entity.getChildren() != null && !entity.getChildren().isEmpty()) {
                count += countAllEntities(entity.getChildren());
            }
        }
        return count;
    }

    private void summarizeEntities(List<DataEntity> entities, Map<String, Integer> summary) {
        for (DataEntity entity : entities) {
            summary.merge(entity.getEntityType(), 1, Integer::sum);
            if (entity.getChildren() != null) {
                summarizeEntities(entity.getChildren(), summary);
            }
        }
    }

    private String nodeToString(Node node) {
        try {
            TransformerFactory tf = TransformerFactory.newInstance();
            tf.setAttribute("http://javax.xml.XMLConstants/property/accessExternalDTD", "");
            tf.setAttribute("http://javax.xml.XMLConstants/property/accessExternalStylesheet", "");
            Transformer transformer = tf.newTransformer();
            transformer.setOutputProperty("omit-xml-declaration", "yes");
            StringWriter writer = new StringWriter();
            transformer.transform(new DOMSource(node), new StreamResult(writer));
            return writer.toString();
        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "Failed to serialize node", e);
            return "<empty/>";
        }
    }

    // --- Standalone XML Processing (for direct usage without SOAP container) ---

    public ImportJob processXmlPayload(String xmlPayload) throws Exception {
        DocumentBuilder builder = createSecureDocumentBuilder();
        Document document = builder.parse(new InputSource(new StringReader(xmlPayload)));

        List<DataEntity> entities = parseEntitiesFromDocument(document);
        List<String> errors = validateEntities(entities);
        long totalRecords = countAllEntities(entities);

        String jobId = UUID.randomUUID().toString();
        String status = errors.isEmpty() ? "COMPLETED" : "COMPLETED_WITH_ERRORS";

        ImportJob job = new ImportJob(jobId, status, totalRecords, totalRecords, entities, errors);
        IMPORT_JOBS.put(jobId, job);

        return job;
    }

    public ImportJob processXmlStream(InputStream xmlStream) throws Exception {
        DocumentBuilder builder = createSecureDocumentBuilder();
        Document document = builder.parse(xmlStream);

        List<DataEntity> entities = parseEntitiesFromDocument(document);
        List<String> errors = validateEntities(entities);
        long totalRecords = countAllEntities(entities);

        String jobId = UUID.randomUUID().toString();
        String status = errors.isEmpty() ? "COMPLETED" : "COMPLETED_WITH_ERRORS";

        ImportJob job = new ImportJob(jobId, status, totalRecords, totalRecords, entities, errors);
        IMPORT_JOBS.put(jobId, job);

        return job;
    }

